package com.pos;
import javax.swing.*; import java.awt.*; import java.sql.*;
public class UserDashboardPanel extends JPanel { private final UserSession s; private final JPanel cards=new JPanel(new GridLayout(2,4,10,10)); public UserDashboardPanel(UserSession s){super(new BorderLayout(10,10));this.s=s;setBorder(BorderFactory.createEmptyBorder(14,14,14,14));JPanel h=new JPanel(new BorderLayout());h.add(UIUtils.title("Customer Dashboard - Welcome, "+s.fullName),BorderLayout.WEST);JButton b=new JButton("Refresh");h.add(b,BorderLayout.EAST);add(h,BorderLayout.NORTH);add(cards,BorderLayout.CENTER);b.addActionListener(e->load());load();}
 private void load(){cards.removeAll();try{int cid=POSService.customerId(s.userId);String[][] q={{"My Orders","SELECT COUNT(*) FROM sales_orders WHERE customer_id="+cid},{"Pending Orders","SELECT COUNT(*) FROM sales_orders WHERE customer_id="+cid+" AND order_status IN ('PENDING','APPROVED')"},{"Balance","SELECT CONCAT('PHP ',FORMAT(COALESCE(SUM(balance),0),2)) FROM sales_orders WHERE customer_id="+cid},{"Loyalty Points","SELECT loyalty_points FROM customer_profiles WHERE customer_id="+cid},{"Payments Pending","SELECT COUNT(*) FROM sales_payments p JOIN sales_orders o ON o.order_id=p.order_id WHERE o.customer_id="+cid+" AND p.status='PENDING'"},{"Returns","SELECT COUNT(*) FROM sales_returns WHERE customer_id="+cid},{"Unread Notices","SELECT COUNT(*) FROM notifications WHERE user_id="+s.userId+" AND status='UNREAD'"},{"Active Products","SELECT COUNT(*) FROM products WHERE status='ACTIVE'"}};try(Connection c=DB.getConnection()){for(String[] x:q){String value="0";try(PreparedStatement p=c.prepareStatement(x[1]);ResultSet r=p.executeQuery()){if(r.next())value=String.valueOf(r.getObject(1));}JPanel card=new JPanel(new BorderLayout());card.setBorder(BorderFactory.createCompoundBorder(BorderFactory.createEtchedBorder(),BorderFactory.createEmptyBorder(12,12,12,12)));JLabel v=new JLabel(value);v.setFont(v.getFont().deriveFont(Font.BOLD,24f));card.add(new JLabel(x[0]),BorderLayout.NORTH);card.add(v,BorderLayout.CENTER);cards.add(card);}}}catch(Exception e){UIUtils.error(this,e);}cards.revalidate();cards.repaint();}
}
